queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasPhotojournalists ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photojournalists } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?type WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasEquipment ?child ; p:hasPhotojournalists ?parent . } GROUP BY ?child }
  ?child p:type ?type .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Photojournalists } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?name ?type WHERE {
  ?photojournalist_equipment a :Photojournalist_Equipment .
  ?equipment a :Equipment .
  ?photojournalist_equipment p:hasEquipment ?equipment .
  ?photojournalists a :Photojournalists .
  ?photojournalist_equipment p:hasPhotojournalists ?photojournalists .
  ?photojournalists p:name ?name .
  ?equipment p:type ?type .
} }
}
